/* ============ APEX//CONTROL · LoginPage surface ============ */

/* Tactical backdrop: slate base + a faint HUD grid + volt/cyan command glows.
   repeating-linear-gradient draws the grid (no background-size needed). */
.auth-bg-image {
    background-color: var(--mud-palette-background) !important;
    background-image:
        radial-gradient(58% 70% at 14% 0%,  rgba(var(--mud-palette-primary-rgb),   0.12), transparent 60%),
        radial-gradient(52% 64% at 92% 102%, rgba(var(--mud-palette-secondary-rgb), 0.12), transparent 60%),
        repeating-linear-gradient(0deg,  rgba(var(--mud-palette-primary-rgb), 0.045) 0 1px, transparent 1px 40px),
        repeating-linear-gradient(90deg, rgba(var(--mud-palette-primary-rgb), 0.045) 0 1px, transparent 1px 40px) !important;
    background-repeat: no-repeat, no-repeat, repeat, repeat !important;
    background-position: center !important;
}
.auth-bg-overlay {
    background: radial-gradient(135% 115% at 50% -12%, transparent 44%, rgba(0,0,0,0.55)) !important;
    opacity: 1 !important;
}

/* Corner theme toggle → angular volt-edged plate */
.auth-theme-toggle .mud-icon-button {
    background: rgba(var(--mud-palette-surface-rgb), 0.7);
    border: 1px solid rgba(var(--mud-palette-primary-rgb), 0.40);
    border-radius: 0;
    clip-path: polygon(0 0, 100% 0, 100% calc(100% - 8px), calc(100% - 8px) 100%, 0 100%);
}

/* ---- Panel ---- */
.ax-login { position: relative; width: 100%; display: flex; justify-content: center; }
.ax-login__announce { position: absolute; bottom: calc(100% + 18px); width: 100%; max-width: 432px; }

.ax-login__panel {
    position: relative;
    overflow: hidden;
    width: 432px;
    max-width: 92vw;
    padding: 36px 34px 22px;
    background:
        linear-gradient(180deg, rgba(var(--mud-palette-primary-rgb), 0.06), rgba(var(--mud-palette-primary-rgb), 0) 36%),
        rgba(var(--mud-palette-surface-rgb), 0.94);
    border: 1px solid rgba(var(--mud-palette-primary-rgb), 0.34);
    /* notch top-right + bottom-left for the asymmetric HUD silhouette */
    clip-path: polygon(0 0, calc(100% - 22px) 0, 100% 22px, 100% 100%, 22px 100%, 0 calc(100% - 22px));
    box-shadow: 0 30px 80px -26px rgba(0,0,0,0.7), inset 0 0 0 1px rgba(var(--mud-palette-primary-rgb), 0.06);
    animation: ax-boot 0.5s cubic-bezier(0.2,0.7,0.2,1) both;
}

/* HUD corner brackets on the two un-notched corners (top-left + bottom-right) */
.ax-frame::before, .ax-frame::after {
    content: "";
    position: absolute;
    width: 20px; height: 20px;
    border: 2px solid rgba(var(--mud-palette-primary-rgb), 0.9);
    pointer-events: none;
    z-index: 2;
}
.ax-frame::before { top: 7px; left: 7px;  border-right: 0; border-bottom: 0; }
.ax-frame::after  { bottom: 7px; right: 7px; border-left: 0;  border-top: 0; }

/* Scanning sweep line */
.ax-login__scan {
    position: absolute; left: 0; right: 0; top: -2%; height: 2px;
    background: linear-gradient(90deg, transparent, rgba(var(--mud-palette-primary-rgb), 0.85), transparent);
    box-shadow: 0 0 12px rgba(var(--mud-palette-primary-rgb), 0.8);
    animation: ax-scan 6.5s linear infinite;
    pointer-events: none;
    z-index: 1;
}

/* ---- Brand ---- */
.ax-login__head { position: relative; z-index: 2; display: flex; align-items: center; gap: 15px; margin-bottom: 20px; }
.ax-login__mark { width: 56px; height: 56px; font-size: 26px; }
.ax-login__id { display: flex; flex-direction: column; min-width: 0; }
.ax-login__name { margin: 0; font-size: 27px; line-height: 1; }
.ax-login__tag { margin: 6px 0 0; color: rgba(var(--mud-palette-secondary-rgb), 1); }

/* ---- Status rule ---- */
.ax-login__rule { position: relative; z-index: 2; display: flex; align-items: center; gap: 10px; margin: 2px 0 22px; }
.ax-login__rule-text { color: var(--mud-palette-text-secondary); }
.ax-login__rule-line { flex: 1; height: 1px; background: linear-gradient(90deg, rgba(var(--mud-palette-primary-rgb), 0.45), transparent); }

/* ---- Form fields → angular, volt focus ---- */
.ax-login__form { position: relative; z-index: 2; }
.ax-login .login-field .mud-input-outlined { background: rgba(var(--mud-palette-background), 0.5); border-radius: 0; }
.ax-login .login-field .mud-input-outlined-border {
    border-color: rgba(var(--mud-palette-primary-rgb), 0.30);
    border-radius: 0;
    transition: border-color .15s ease, box-shadow .15s ease;
}
.ax-login .login-field .mud-input-outlined:focus-within .mud-input-outlined-border {
    border-color: rgba(var(--mud-palette-primary-rgb), 1) !important;
    border-width: 1px !important;
    box-shadow: 0 0 0 2px rgba(var(--mud-palette-primary-rgb), 0.22), 0 0 16px -2px rgba(var(--mud-palette-primary-rgb), 0.4);
}

/* ---- Submit → volt plate, dark contrast text, notched corner ---- */
.ax-login .login-submit-btn {
    background: rgba(var(--mud-palette-primary-rgb), 1) !important;
    color: var(--mud-palette-primary-text) !important;
    border: 0 !important;
    border-radius: 0 !important;
    clip-path: polygon(0 0, 100% 0, 100% calc(100% - 9px), calc(100% - 9px) 100%, 0 100%);
    height: 46px;
    margin-top: 6px;
    font-weight: 800;
    letter-spacing: 0.16em;
    text-transform: uppercase;
    box-shadow: 0 0 28px -6px rgba(var(--mud-palette-primary-rgb), 0.7);
    transition: filter .15s ease, box-shadow .2s ease, transform .1s ease;
}
.ax-login .login-submit-btn:hover { filter: brightness(1.1); box-shadow: 0 0 38px -4px rgba(var(--mud-palette-primary-rgb), 0.85); }
.ax-login .login-submit-btn:active { transform: translateY(1px); }
.ax-login .login-forgot-btn { font-size: 12px; letter-spacing: 0.04em; color: rgba(var(--mud-palette-secondary-rgb), 1); }

/* ---- Footer row ---- */
.ax-login__foot {
    position: relative; z-index: 2;
    display: flex; align-items: center; gap: 9px;
    margin-top: 18px; padding-top: 15px;
    border-top: 1px solid rgba(var(--mud-palette-primary-rgb), 0.22);
}
.ax-login__foot-ico { font-size: 12px; color: rgba(var(--mud-palette-primary-rgb), 1); }
.ax-login__foot-text { color: var(--mud-palette-text-secondary); }
.ax-login__lang { margin-left: auto; }
.ax-login__lang .mud-input-control { margin: 0; }

.auth-footer { color: var(--mud-palette-text-secondary); opacity: 0.7; letter-spacing: 0.06em; text-transform: uppercase; font-size: 11px; }

/* ============ APEX//CONTROL · Shell surface (authenticated chrome) ============
   Composed {% component "shell" %} so MudBlazor owns layout coordination
   (no drawer-pin needed). Every rule is scoped via :has(.mud-appbar) so none
   of it leaks onto the login page (which shares the .mud-layout wrapper).
   FULL-TRUST → clip-path notches + the HUD grid render raw. */

/* ---- Slate command-deck backdrop + faint HUD grid ---- */
.mud-layout:has(.mud-appbar) {
    background-color: var(--mud-palette-background) !important;
    background-image:
        radial-gradient(46% 56% at 8% 0%,   rgba(var(--mud-palette-primary-rgb),   0.10), transparent 60%),
        radial-gradient(44% 60% at 99% 4%,   rgba(var(--mud-palette-secondary-rgb), 0.08), transparent 58%),
        repeating-linear-gradient(0deg,  rgba(var(--mud-palette-primary-rgb), 0.035) 0 1px, transparent 1px 44px),
        repeating-linear-gradient(90deg, rgba(var(--mud-palette-primary-rgb), 0.035) 0 1px, transparent 1px 44px) !important;
    background-attachment: fixed, fixed, fixed, fixed !important;
    background-repeat: no-repeat, no-repeat, repeat, repeat !important;
}
/* Transparent so the HUD-grid backdrop shows through. isolation:isolate makes
   this a stacking context so the game-service hero's z-index:-10 background
   image stays contained ABOVE this opaque backdrop — without it the negative
   z-index escapes to the root stacking context and the .mud-layout
   background-color paints over the image (it only "worked" on the default
   theme because that layout is transparent). */
.mud-layout:has(.mud-appbar) .mud-main-content { background: transparent !important; isolation: isolate; }

/* ---- Top app bar → dark plate, volt underline ---- */
.mud-layout:has(.mud-appbar) .mud-appbar {
    background: rgba(var(--mud-palette-surface-rgb), 0.86) !important;
    border-bottom: 1px solid rgba(var(--mud-palette-primary-rgb), 0.5);
    box-shadow: 0 1px 0 0 rgba(var(--mud-palette-primary-rgb), 0.18), 0 10px 30px -18px rgba(0,0,0,0.7);
}

/* ---- Navigation drawer → dark plate, volt right edge ---- */
.mud-layout:has(.mud-appbar) .mud-drawer {
    background: rgba(var(--mud-palette-surface-rgb), 0.92) !important;
    border-right: 1px solid rgba(var(--mud-palette-primary-rgb), 0.32);
}
.mud-layout:has(.mud-appbar) .mud-drawer-content { overflow-x: hidden; }

/* ---- Nav links: angular, volt hover, volt left rail on active ---- */
.mud-layout:has(.mud-appbar) .mud-nav-link {
    border-radius: 0;
    margin: 1px 8px;
    border-left: 2px solid transparent;
    transition: background-color .12s ease, color .12s ease, border-color .12s ease;
}
.mud-layout:has(.mud-appbar) .mud-nav-link:hover {
    background: rgba(var(--mud-palette-primary-rgb), 0.08);
    border-left-color: rgba(var(--mud-palette-primary-rgb), 0.5);
}
.mud-layout:has(.mud-appbar) .mud-nav-link.active {
    background: rgba(var(--mud-palette-primary-rgb), 0.12);
    color: rgba(var(--mud-palette-primary-rgb), 1) !important;
    border-left-color: rgba(var(--mud-palette-primary-rgb), 1);
    box-shadow: inset 0 0 22px -10px rgba(var(--mud-palette-primary-rgb), 0.6);
}
.mud-layout:has(.mud-appbar) .mud-nav-link.active .mud-nav-link-icon { color: rgba(var(--mud-palette-primary-rgb), 1) !important; }

/* Collapsed (mini) rail: the expanded h-margin + left rail shift the icon right and the drawer's
   overflow-x:hidden clips it — drop them in the closed state so the icon re-centers in the rail. */
.mud-layout:has(.mud-appbar) .mud-drawer--closed .mud-nav-link { margin-left: 0; margin-right: 0; border-left-width: 0; }

/* ---- Content panels → angular notched HUD plates (scoped to main content so
   dialogs / popovers / menus, which render in a portal, stay opaque & un-clipped) ----
   :not([style*="background-image"]) skips papers that set their own inline
   background image (the game/service hero, list-row + grid cards) — otherwise
   this !important background + clip-path overpaints / notches their url. */
.mud-layout:has(.mud-appbar) .mud-main-content .mud-paper:not(.mud-table-container):not(.mud-table):not(.mud-menu-list):not(.mud-list):not([style*="background-image"]) {
    background:
        linear-gradient(180deg, rgba(var(--mud-palette-primary-rgb), 0.05), rgba(var(--mud-palette-primary-rgb), 0) 30%),
        rgba(var(--mud-palette-surface-rgb), 0.9) !important;
    border: 1px solid rgba(var(--mud-palette-primary-rgb), 0.2);
    border-radius: 0 !important;
    /* small notch on the top-right corner — the HUD silhouette without clipping content */
    clip-path: polygon(0 0, calc(100% - 16px) 0, 100% 16px, 100% 100%, 0 100%);
    box-shadow: inset 0 2px 0 0 rgba(var(--mud-palette-primary-rgb), 0.35);
}
/* Inner nested papers stay flat (no double tint / notch) — but never blank out
   a nested card that carries its own inline background image (e.g. the grid /
   list game cards live inside an outer paper). */
.mud-layout:has(.mud-appbar) .mud-main-content .mud-paper .mud-paper:not([style*="background-image"]) {
    background: transparent !important;
    border: 0;
    clip-path: none;
    box-shadow: none;
}

/* ---- In-app primary buttons → volt plate, dark contrast text ---- */
.mud-layout:has(.mud-appbar) .mud-main-content .mud-button-filled-primary {
    background: rgba(var(--mud-palette-primary-rgb), 1) !important;
    color: var(--mud-palette-primary-text) !important;
    border: 0 !important;
    border-radius: 0 !important;
    font-weight: 700;
    letter-spacing: 0.04em;
    box-shadow: 0 0 24px -8px rgba(var(--mud-palette-primary-rgb), 0.7);
}

/* ============ APEX//CONTROL · Shell.DrawerFooter (operator block + our own logout) ============ */

/* Hide the compiled drawer's default Profile + Logout block — we render our own, on-brand. */
.mud-drawer .mud-navmenu.mt-auto { display: none; }

.ax-df {
    display: flex; flex-direction: column; gap: 3px;
    margin: auto 10px 12px;            /* margin-top:auto pins the block to the drawer bottom */
    padding: 6px;
    background: rgba(var(--mud-palette-primary-rgb), 0.07);
    border: 1px solid rgba(var(--mud-palette-primary-rgb), 0.26);
    clip-path: polygon(0 0, calc(100% - 12px) 0, 100% 12px, 100% 100%, 12px 100%, 0 calc(100% - 12px));
}

.ax-df__user {
    display: flex; align-items: center; gap: 11px;
    padding: 7px 8px;
    text-decoration: none; color: inherit;
    transition: background-color .12s ease;
}
.ax-df__user:hover { background: rgba(var(--mud-palette-primary-rgb), 0.12); }
.ax-df__avatar {
    width: 34px; height: 34px; flex: none;
    display: inline-flex; align-items: center; justify-content: center;
    background: rgba(var(--mud-palette-surface-rgb), 1);
    border: 1px solid rgba(var(--mud-palette-primary-rgb), 0.5);
    color: rgba(var(--mud-palette-primary-rgb), 1);
    font-size: 15px;
    clip-path: polygon(0 0, 100% 0, 100% calc(100% - 7px), calc(100% - 7px) 100%, 0 100%);
}
.ax-df__meta { display: flex; flex-direction: column; min-width: 0; overflow: hidden; }
.ax-df__name {
    font-size: 13px; font-weight: 700;
    color: var(--mud-palette-text-primary);
    white-space: nowrap; overflow: hidden; text-overflow: ellipsis;
}
.ax-df__role { margin-top: 1px; color: var(--mud-palette-text-secondary); font-size: 10px; }
.ax-df__led { margin-left: auto; }

.ax-df__logout {
    display: flex; align-items: center; gap: 11px;
    padding: 8px;
    text-decoration: none;
    color: var(--mud-palette-text-secondary);
    font-size: 12px; font-weight: 700; letter-spacing: 0.08em; text-transform: uppercase;
    transition: background-color .12s ease, color .12s ease;
}
.ax-df__logout:hover { background: rgba(255,82,82,0.12); color: #ff5252; }
.ax-df__logout-ico { width: 34px; flex: none; text-align: center; font-size: 14px; }

/* Collapsed (mini) drawer → icons only, centered */
.mud-drawer--closed .ax-df { margin: auto 6px 12px; padding: 6px; background: transparent; border: 0; clip-path: none; }
.mud-drawer--closed .ax-df__user { justify-content: center; padding: 6px; }
.mud-drawer--closed .ax-df__logout { justify-content: center; padding: 6px; }
.mud-drawer--closed .ax-df__logout-ico { width: auto; }
.mud-drawer--closed .ax-df__meta,
.mud-drawer--closed .ax-df__led,
.mud-drawer--closed .ax-df__logout-text { display: none; }

/* ============ APEX//CONTROL · Shell.DrawerHeader (brand zone, above the nav) ============ */
.ax-dh { position: relative; overflow: hidden; display: flex; align-items: center; gap: 12px; padding: 16px 14px 13px; border-bottom: 1px solid rgba(var(--mud-palette-primary-rgb), 0.16); }
.ax-dh__mark { position: relative; z-index: 2; width: 40px; height: 40px; font-size: 18px; }
.ax-dh__text { position: relative; z-index: 2; display: flex; flex-direction: column; min-width: 0; overflow: hidden; white-space: nowrap; }
.ax-dh__name { font-size: 16px; line-height: 1.05; }
.ax-dh__tag { margin-top: 4px; color: rgba(var(--mud-palette-secondary-rgb), 1); }

/* Scanning sweep line — the same HUD scan as the login panel (shared base.css @keyframes ax-scan).
   Sits behind the brand content (z-index 1 < 2); the container is overflow:hidden so the 12px glow
   is clipped to the header. Period is shorter than login (4s vs 6.5s) because the drawer header is
   far shorter — at 6.5s the line would barely creep across ~70px. */
.ax-dh__scan {
    position: absolute; left: 0; right: 0; top: -2%; height: 2px;
    background: linear-gradient(90deg, transparent, rgba(var(--mud-palette-primary-rgb), 0.85), transparent);
    box-shadow: 0 0 12px rgba(var(--mud-palette-primary-rgb), 0.8);
    animation: ax-scan 4s linear infinite;
    pointer-events: none;
    z-index: 1;
}

/* Collapsed (mini) drawer → reticle plate only, centered */
.mud-drawer--closed .ax-dh { justify-content: center; padding-left: 0; padding-right: 0; }
.mud-drawer--closed .ax-dh__text { display: none; }

/* ============ APEX//CONTROL · Shell.Footer (HUD status bar) ============ */
.ax-ft {
    display: flex; align-items: center; gap: 12px;
    width: 100%; padding: 0 14px;
    font-size: 12px; color: var(--mud-palette-text-secondary);
    border-top: 1px solid rgba(var(--mud-palette-primary-rgb), 0.18);
}
.ax-ft__brand { display: inline-flex; align-items: center; gap: 7px; flex: none; }
.ax-ft__reticle { color: rgba(var(--mud-palette-primary-rgb), 1); font-size: 12px; filter: drop-shadow(0 0 5px rgba(var(--mud-palette-primary-rgb), 0.7)); }
.ax-ft__name { font-size: 12px; }

/* Page-driven live service stats fill the middle; the section's own MudSpacer right-aligns its status. */
.ax-ft__resources { flex: 1; display: flex; align-items: center; min-width: 0; overflow: hidden; }

.ax-ft__ver {
    flex: none;
    color: rgba(var(--mud-palette-primary-rgb), 1);
    font-variant-numeric: tabular-nums;
    padding: 2px 9px;
    background: rgba(var(--mud-palette-primary-rgb), 0.10);
    border: 1px solid rgba(var(--mud-palette-primary-rgb), 0.3);
    clip-path: polygon(0 0, 100% 0, 100% calc(100% - 6px), calc(100% - 6px) 100%, 0 100%);
}

/* ============ APEX//CONTROL · Shell.MenuLinks (custom links appended to the nav) ============ */
/* The .mud-nav-link anchor inherits native nav styling + the Shell surface's
   angular hover/active-rail rules. Only the FA icon needs sizing to match MudBlazor's
   24px nav icons; mud-icon-root is load-bearing for the mini-collapse rail. */
.ax-ml-ico { font-size: 24px; width: 24px; text-align: center; }

/* ============ APEX//CONTROL · Shell.TopBarEnd (SYS health + uplink readout, after the dark-mode toggle) ============ */
.ax-te { display: inline-flex; align-items: center; gap: 8px; margin-left: 8px; margin-right: 4px; }

/* System-health chip — sits bare beside the uplink pill (the chip is its own colored status pill, so it
   needs no frame). Squared to read as an angular HUD module; the component bakes in `margin-left:8px`,
   so drop it and let the flex gap own the spacing. It self-gates on SystemHealth.View → renders nothing
   for users without it, so `:has()` collapses the empty wrapper (no stray gap before the uplink pill). */
.ax-te__health { display: inline-flex; align-items: center; }
.ax-te__health:not(:has(.mud-chip)) { display: none; }
.ax-te__health .mud-chip { margin-left: 0 !important; border-radius: 0 !important; }

.ax-te__pill {
    display: inline-flex; align-items: center; gap: 8px;
    padding: 4px 10px;
    background: rgba(var(--mud-palette-surface-rgb), 0.7);
    border: 1px solid rgba(var(--mud-palette-primary-rgb), 0.36);
    clip-path: polygon(0 0, calc(100% - 8px) 0, 100% 8px, 100% 100%, 8px 100%, 0 calc(100% - 8px));
}
.ax-te__label { color: var(--mud-palette-text-secondary); }
.ax-te__indicator { display: inline-flex; align-items: center; }
/* The connection dot rides 3px high otherwise: MudTooltip's root is display:block, so its inline-flex
   icon activator baseline-aligns in a taller line-box. Flex-center the root + kill the line-box. */
.ax-te__indicator .mud-tooltip-root { display: flex; align-items: center; line-height: 0; }
